#include <stdio.h>
#include <stdlib.h>
#include <time.h>

int gcd(int a, int b) {
    if (b == 0) return a;
    return gcd(b, a % b);
}

int simulate_game(int* cards, int n) {
    int current = 0;
    while (1) {
        int move = -1;
        for (int i = 0; i < n; i++) {
            if (cards[i] != -1) {
                int new_current = gcd(current, cards[i]);
                if (new_current != 1) {
                    move = i;
                    break;
                }
            }
        }
        if (move == -1) return 0;
        current = gcd(current, cards[move]);
        cards[move] = -1;
        if (current == 1) return 1;
    }
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int n;
        scanf("%d", &n);
        int* cards = (int*) malloc(n * sizeof(int));
        for (int i = 0; i < n; i++) {
            scanf("%d", &cards[i]);
        }
        int optimal = simulate_game(cards, n);
        int random = 0;
        int total = 10000;
        srand(time(NULL));
        for (int i = 0; i < total; i++) {
            int* random_cards = (int*) malloc(n * sizeof(int));
            for (int j = 0; j < n; j++) {
                random_cards[j] = cards[j];
            }
            int current = 0;
            while (1) {
                int move = -1;
                int count = 0;
                for (int j = 0; j < n; j++) {
                    if (random_cards[j] != -1) {
                        count++;
                    }
                }
                if (count == 0) break;
                int index = rand() % count;
                int k = 0;
                for (int j = 0; j < n; j++) {
                    if (random_cards[j] != -1) {
                        if (k == index) {
                            move = j;
                            break;
                        }
                        k++;
                    }
                }
                current = gcd(current, random_cards[move]);
                random_cards[move] = -1;
                if (current == 1) {
                    random++;
                    break;
                }
            }
            free(random_cards);
        }
        printf("%d %.4f\n", optimal, (double) random / total);
        free(cards);
    }
    return 0;
}

