import java.util.Scanner;
import java.util.Random;

public class Main {
    public static int gcd(int a, int b) {
        if (b == 0) return a;
        return gcd(b, a % b);
    }

    public static int simulateGame(int[] cards) {
        int current = 0;
        while (true) {
            int move = -1;
            for (int i = 0; i < cards.length; i++) {
                if (cards[i] != -1) {
                    int newCurrent = gcd(current, cards[i]);
                    if (newCurrent != 1) {
                        move = i;
                        break;
                    }
                }
            }
            if (move == -1) return 0;
            current = gcd(current, cards[move]);
            cards[move] = -1;
            if (current == 1) return 1;
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int[] cards = new int[n];
            for (int i = 0; i < n; i++) {
                cards[i] = scanner.nextInt();
            }
            int optimal = simulateGame(cards);
            int random = 0;
            int total = 10000;
            Random randomGenerator = new Random();
            for (int i = 0; i < total; i++) {
                int[] randomCards = cards.clone();
                int current = 0;
                while (true) {
                    int move = -1;
                    int count = 0;
                    for (int j = 0; j < n; j++) {
                        if (randomCards[j] != -1) {
                            count++;
                        }
                    }
                    if (count == 0) break;
                    int index = randomGenerator.nextInt(count);
                    int k = 0;
                    for (int j = 0; j < n; j++) {
                        if (randomCards[j] != -1) {
                            if (k == index) {
                                move = j;
                                break;
                            }
                            k++;
                        }
                    }
                    current = gcd(current, randomCards[move]);
                    randomCards[move] = -1;
                    if (current == 1) {
                        random++;
                        break;
                    }
                }
            }
            System.out.println(optimal + " " + (double) random / total);
        }
    }
}

